// Parse Claude response, fallback to regex if Claude failed
const claudeOutput = $input.first().json;
const inputData = $('입력 준비').first().json;

let destination = inputData.text;
let transportMode = inputData.userTransportMode;

// Try to parse Claude's response
try {
  const content = claudeOutput?.content?.[0]?.text || '';
  if (content) {
    const parsed = JSON.parse(content.trim());
    if (parsed.destination) destination = parsed.destination;
    if (parsed.transportMode) transportMode = parsed.transportMode;
    console.log('Claude parsed:', parsed);
  }
} catch (e) {
  console.log('Claude parsing failed, using regex fallback:', e.message);

  // Regex fallback
  const text = inputData.text;
  if (/대중교통|버스|지하철|전철|기차|KTX|SRT/.test(text)) transportMode = 'transit';
  else if (/자동차|차로|드라이브|운전|차량/.test(text)) transportMode = 'car';

  const patterns = [
    /(.+?)(?:으로|로)\s*(?:가기|가는\s*길|길찾기|안내)/,
    /(.+?)(?:에|까지)\s*(?:가기|가는\s*길|길찾기|안내)/,
    /(.+?)\s*(?:가는\s*길)/,
    /(.+?)\s*(?:찾아줘|찾아주세요|알려줘|알려주세요)/,
    /(?:대중교통으로|자동차로|버스로|지하철로)?\s*(.+?)(?:으로|로|에|까지)?\s*(?:가기|가자|갈래|가고\s*싶어)/,
  ];
  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match && match[1]) {
      destination = match[1].replace(/^(?:대중교통으로|자동차로|버스로|지하철로|도보로)\s*/, '').trim();
      break;
    }
  }
}

console.log('Final:', { destination, transportMode });

return [{
  json: {
    destination,
    transportMode,
    userLat: inputData.userLat,
    userLng: inputData.userLng,
    originalText: inputData.text,
  }
}];

// Format Naver Local Search results and attach metadata
const data = $input.first().json;
const parsedData = $('목적지 파싱').first().json;

if (!data || !data.items || data.items.length === 0) {
  return [{ json: { candidates: [], destination: parsedData.destination, transportMode: parsedData.transportMode } }];
}

function convertCoords(mapx, mapy) {
  return {
    lat: parseInt(mapy) / 10000000,
    lng: parseInt(mapx) / 10000000,
  };
}

function stripHtml(str) {
  return (str || '').replace(/<[^>]*>/g, '');
}

// Haversine distance in meters
function haversine(lat1, lng1, lat2, lng2) {
  const R = 6371000;
  const toRad = d => d * Math.PI / 180;
  const dLat = toRad(lat2 - lat1);
  const dLng = toRad(lng2 - lng1);
  const a = Math.sin(dLat/2)**2 + Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLng/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

const userLat = parsedData.userLat || 37.5665;
const userLng = parsedData.userLng || 126.9780;

const candidates = data.items.map((item, index) => {
  const { lat, lng } = convertCoords(item.mapx, item.mapy);
  const distanceM = Math.round(haversine(userLat, userLng, lat, lng));
  const distanceLabel = distanceM < 1000
    ? distanceM + 'm'
    : (distanceM / 1000).toFixed(1) + 'km';

  return {
    index: index + 1,
    name: stripHtml(item.title),
    address: stripHtml(item.roadAddress) || stripHtml(item.address),
    roadAddress: stripHtml(item.roadAddress),
    jibunAddress: stripHtml(item.address),
    category: stripHtml(item.category),
    telephone: item.telephone || '',
    link: item.link || '',
    lat,
    lng,
    distanceM,
    distanceLabel,
  };
});

// Sort by distance
candidates.sort((a, b) => a.distanceM - b.distanceM);
candidates.forEach((c, i) => { c.index = i + 1; });

return [{
  json: {
    candidates,
    destination: parsedData.destination,
    transportMode: parsedData.transportMode,
  }
}];
